const item = $input.first();

let image;
let audio;
let prompt = '.';
let source = 'manual';
let imageFile = 'portrait';
let audioFile = 'audio';

if (item.json?.source === 'webhook') {
  const binary = item.binary || {};
  image = binary[item.json.image_key];
  audio = binary[item.json.audio_key];
  prompt = item.json.prompt || '.';
  source = 'webhook';
  imageFile = item.json.image_file || item.json.image_key;
  audioFile = item.json.audio_file || item.json.audio_key;
} else {
  const imageBinary = $('Read Portrait Image').first().binary || {};
  const audioBinary = $('Read Audio File').first().binary || {};
  const imageKey = Object.keys(imageBinary)[0];
  const audioKey = Object.keys(audioBinary)[0];
  image = imageBinary[imageKey];
  audio = audioBinary[audioKey];
  imageFile = image?.fileName || imageKey || 'portrait';
  audioFile = audio?.fileName || audioKey || 'audio';
}

if (!image || !audio) {
  throw new Error('Missing portrait image or audio file.');
}

const imageMime = image.mimeType || 'image/jpeg';
const audioMime = audio.mimeType || 'audio/mpeg';

return [{
  json: {
    image_url: `data:${imageMime};base64,${image.data}`,
    audio_url: `data:${audioMime};base64,${audio.data}`,
    prompt,
    model_id: 'fal-ai/kling-video/ai-avatar/v2/pro',
    image_file: imageFile,
    audio_file: audioFile,
    source,
  },
}];

const create = $input.first().json;
const prep = $('Prepare Media URLs').first().json;

if (!create.request_id) {
  return [{
    json: {
      success: false,
      stage: 'create_avatar',
      error: create.detail || create.message || create.error || 'No request_id returned from Kling Avatar API',
      source: prep.source || 'manual',
      raw: create,
    },
  }];
}

return [{
  json: {
    success: true,
    request_id: create.request_id,
    status_url: create.status_url,
    response_url: create.response_url,
    cancel_url: create.cancel_url,
    model_id: prep.model_id,
    image_file: prep.image_file,
    audio_file: prep.audio_file,
    source: prep.source || 'manual',
    submitted_at: new Date().toISOString(),
  },
}];

const result = $input.first().json;
const meta = $('Validate Create Response').first().json;

const videoUrl = result?.video?.url || result?.data?.video?.url;
const duration = result?.video?.duration || result?.duration || result?.data?.duration;

if (!videoUrl) {
  return [{
    json: {
      success: false,
      stage: 'get_result',
      error: 'Video URL not found in API result',
      request_id: meta.request_id,
      source: meta.source || 'manual',
      raw: result,
    },
  }];
}

return [{
  json: {
    success: true,
    request_id: meta.request_id,
    video_url: videoUrl,
    duration_seconds: duration,
    image_file: meta.image_file,
    audio_file: meta.audio_file,
    source: meta.source || 'manual',
    completed_at: new Date().toISOString(),
    message: 'Kling AI avatar lip-sync video generated successfully.',
  },
}];

const status = $input.first().json;
const meta = $('Validate Create Response').first().json;
return [{
  json: {
    success: false,
    stage: 'poll_status',
    source: meta.source || 'manual',
    request_id: meta.request_id,
    status: status.status,
    error: status.error || status.detail || 'Avatar generation failed on Kling API',
    raw: status,
  },
}];

const FAL_MODEL = 'fal-ai/kling-video/ai-avatar/v2/pro';
const meta = $('Validate Create Response').first().json;
const requestId = meta.request_id;
const falKey = $env.FAL_API_KEY || $env.FAL_KEY;

if (!falKey) {
  throw new Error('Missing FAL_API_KEY environment variable on n8n server.');
}

const maxAttempts = 36;
const delayMs = 15000;
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

for (let attempt = 1; attempt <= maxAttempts; attempt++) {
  const statusRes = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://queue.fal.run/${FAL_MODEL}/requests/${requestId}/status`,
    headers: { Authorization: `Key ${falKey}` },
    json: true,
    timeout: 60000,
  });

  const status = String(statusRes.status || '').toUpperCase();

  if (status === 'COMPLETED') {
    const result = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://queue.fal.run/${FAL_MODEL}/requests/${requestId}`,
      headers: { Authorization: `Key ${falKey}` },
      json: true,
      timeout: 60000,
    });

    const videoUrl = result?.video?.url || result?.data?.video?.url;
    if (!videoUrl) {
      throw new Error('Job completed but video URL was not returned.');
    }

    return [{
      json: {
        success: true,
        request_id: requestId,
        video_url: videoUrl,
        duration_seconds: result?.duration || result?.data?.duration,
        image_file: meta.image_file,
        audio_file: meta.audio_file,
        poll_attempts: attempt,
        source: meta.source || 'manual',
        completed_at: new Date().toISOString(),
        message: 'Kling AI avatar lip-sync video generated successfully.',
      },
    }];
  }

  if (status === 'FAILED') {
    throw new Error(statusRes.error || statusRes.detail || 'Kling avatar generation failed.');
  }

  if (attempt < maxAttempts) {
    await sleep(delayMs);
  }
}

throw new Error(`Timed out after ${maxAttempts} polling attempts (~${Math.round((maxAttempts * delayMs) / 60000)} minutes).`);

const err = $input.first().json;
return [{
  json: {
    success: false,
    stage: err.stage || 'create_avatar',
    source: $('Validate Create Response').first()?.json?.source || $('Parse Webhook Upload').first()?.json?.source || 'manual',
    error: err.error || err.message || 'Create avatar request failed',
    raw: err,
  },
}];

const item = $input.first();
const binary = item.binary || {};
const body = item.json.body || item.json;

const imageKey = ['portrait', 'image', 'photo']
  .find((k) => binary[k] && String(binary[k].mimeType || '').startsWith('image/'))
  || Object.keys(binary).find((k) => String(binary[k].mimeType || '').startsWith('image/'));

const audioKey = ['audio', 'speech', 'voice']
  .find((k) => binary[k] && String(binary[k].mimeType || '').startsWith('audio/'))
  || Object.keys(binary).find((k) => String(binary[k].mimeType || '').startsWith('audio/'));

const errors = [];
if (!imageKey) errors.push('portrait image file is required (field: portrait)');
if (!audioKey) errors.push('audio file is required (field: audio)');

if (errors.length) {
  return [{ json: { valid: false, errors, source: 'webhook' } }];
}

return [{
  json: {
    valid: true,
    source: 'webhook',
    image_key: imageKey,
    audio_key: audioKey,
    prompt: String(body.prompt || '.').trim() || '.',
    image_file: binary[imageKey].fileName || imageKey,
    audio_file: binary[audioKey].fileName || audioKey,
  },
  binary,
}];

const data = $input.first().json;
return [{
  json: {
    success: false,
    stage: 'upload_validation',
    source: 'webhook',
    errors: data.errors || ['Invalid upload'],
    message: 'Please upload portrait image and audio file.',
  },
}];

const data = $input.first().json;
return [{ json: {
  success: data.success === true,
  request_id: data.request_id,
  video_url: data.video_url,
  duration_seconds: data.duration_seconds,
  message: data.message || data.error || 'Request processed',
  error: data.error,
  stage: data.stage,
  source: data.source || 'webhook',
}}];
